// src/pages/Home.jsx
import React, { useState, useEffect } from 'react';
import CourseCard from '../components/CourseCard';
// Remove this line: import './Home.css';

const Home = () => {
  const [courses, setCourses] = useState([]);

  useEffect(() => {
    // Mock data
    setCourses([
      { id: 1, name: 'Data Structures', branch: 'CSE', semester: 3 },
      { id: 2, name: 'Digital Electronics', branch: 'ECE', semester: 2 },
      { id: 3, name: 'Thermodynamics', branch: 'Mechanical', semester: 3 },
      { id: 4, name: 'Web Development', branch: 'CSE', semester: 5 },
      { id: 5, name: 'Circuit Theory', branch: 'EEE', semester: 2 },
      { id: 6, name: 'Engineering Maths', branch: 'All', semester: 1 },
    ]);
  }, []);

  return (
    <div style={styles.container}>
      {/* Hero Section */}
      <div style={styles.heroSection}>
        <h1 style={styles.heroTitle}>Welcome to College Notes Hub</h1>
        <p style={styles.heroSubtitle}>Your one-stop destination for notes, PYQs, syllabus and study materials</p>
        
        {/* Search Bar */}
        <div style={styles.searchContainer}>
          <input
            type="text"
            placeholder="Search courses, notes, PYQs..."
            style={styles.searchInput}
          />
          <button style={styles.searchButton}>🔍 Search</button>
        </div>
      </div>

      {/* Stats Section */}
      <div style={styles.statsSection}>
        <div style={styles.statsGrid}>
          <div style={styles.statCard}>
            <h3 style={styles.statNumber}>500+</h3>
            <p style={styles.statLabel}>Notes</p>
          </div>
          <div style={styles.statCard}>
            <h3 style={styles.statNumber}>1000+</h3>
            <p style={styles.statLabel}>PYQs</p>
          </div>
          <div style={styles.statCard}>
            <h3 style={styles.statNumber}>50+</h3>
            <p style={styles.statLabel}>Courses</p>
          </div>
          <div style={styles.statCard}>
            <h3 style={styles.statNumber}>2000+</h3>
            <p style={styles.statLabel}>Downloads</p>
          </div>
        </div>
      </div>

      {/* Courses Section */}
      <h2 style={styles.sectionTitle}>Featured Courses</h2>
      <div style={styles.coursesGrid}>
        {courses.map(course => (
          <CourseCard key={course.id} course={course} />
        ))}
      </div>
      
      <div style={styles.viewAll}>
        <button style={styles.viewAllBtn}>View All Courses →</button>
      </div>
    </div>
  );
};

// Inline styles (CSS file ki jagah)
const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)',
    padding: '20px'
  },
  heroSection: {
    textAlign: 'center',
    padding: '50px 20px',
    background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
    color: 'white',
    borderRadius: '15px',
    marginBottom: '30px',
    boxShadow: '0 10px 30px rgba(0,0,0,0.2)'
  },
  heroTitle: {
    fontSize: '2.5rem',
    fontWeight: 'bold',
    marginBottom: '1rem'
  },
  heroSubtitle: {
    fontSize: '1.2rem',
    opacity: 0.9,
    marginBottom: '2rem'
  },
  searchContainer: {
    maxWidth: '600px',
    margin: '0 auto',
    display: 'flex',
    gap: '10px'
  },
  searchInput: {
    flex: 1,
    padding: '15px 20px',
    borderRadius: '25px',
    border: 'none',
    fontSize: '1rem',
    boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
  },
  searchButton: {
    padding: '0 30px',
    borderRadius: '25px',
    border: 'none',
    background: '#ff6b6b',
    color: 'white',
    fontWeight: 'bold',
    cursor: 'pointer',
    fontSize: '1rem'
  },
  statsSection: {
    background: 'white',
    padding: '30px',
    borderRadius: '15px',
    marginBottom: '30px',
    boxShadow: '0 5px 15px rgba(0,0,0,0.1)'
  },
  statsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(4, 1fr)',
    gap: '20px'
  },
  statCard: {
    textAlign: 'center',
    padding: '20px',
    borderRadius: '10px',
    background: '#f8f9fa'
  },
  statNumber: {
    fontSize: '2rem',
    color: '#4f46e5',
    marginBottom: '0.5rem'
  },
  statLabel: {
    color: '#666',
    fontSize: '1rem'
  },
  sectionTitle: {
    fontSize: '2rem',
    textAlign: 'center',
    margin: '30px 0',
    color: '#333'
  },
  coursesGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
    gap: '25px',
    marginBottom: '30px'
  },
  viewAll: {
    textAlign: 'center',
    marginTop: '40px'
  },
  viewAllBtn: {
    padding: '12px 30px',
    background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
    color: 'white',
    border: 'none',
    borderRadius: '25px',
    fontSize: '1.1rem',
    fontWeight: 'bold',
    cursor: 'pointer',
    transition: 'all 0.3s'
  }
};

export default Home;
